INSERT INTO ingestion_runs (
  pipeline, status, started_at, finished_at,
  records_written, source_attribution, notes
) VALUES (
  'migration_072_installation_history_tier1', 'success', NOW(), NOW(),
  (SELECT COUNT(*) FROM installation_history WHERE
    (asset_class='wind_onshore' AND country IN ('DE','ES','FR','DK','NL','IT','SE','PL','BR','AU','MX','TR'))
    OR asset_class='wind_offshore'
    OR asset_class='solar'
    OR asset_class='bess'),
  'WindEurope Statistics, GWEC Global Wind Reports, IEA-PVPS Snapshot of Global PV Markets, SolarPower Europe Global Market Outlook, IRENA Renewable Capacity Statistics 2025, BNEF Energy Storage Outlook, EASE-Frith European Market Monitor on Energy Storage, EIA Form 860, BOEM, Modo Energy GB BESS index, Clean Energy Council Australia, national regulators (BNetzA, REE, RTE, Energistyrelsen, Terna, CBS, Energimyndigheten, URE, ANEEL, CRE/CENACE, TEIAS, Taiwan MoEA, METI/ANRE, Eirgrid).',
  'Migration 072 — Tier 1 expansion. Wind onshore (DE/ES/FR/DK/NL/IT/SE/PL/BR/AU/MX/TR), wind offshore (GB/DE/NL/DK/BE/US/TW/FR), solar (DE/ES/IT/FR/GB/NL/BE/AU/JP/US), BESS w/ duration (GB/US/DE/AU/IT/ES/IE/KR/JP). Annual values cross-validated against IRENA Capacity Statistics 2025 cumulative totals; all ratios within ±10% except: wind_onshore/MX (~88% — IRENA cumulative ~7.7 GW vs sum ~6.8 GW; gap reflects pre-2007 demonstration projects + small DG that ANEEL-equivalent CRE registry attributes by older commissioning year), wind_offshore/NL (~92% — 2007 Egmond aan Zee 108 MW + 2009 Princess Amalia 120 MW + 2015 Luchterduinen + 2019/2022/2023 Borssele/Hollandse Kust matches IRENA 4.7 GW cumulative), bess/KR (lumpy — 2017-2018 ESS-fire moratorium distorts back-series; 2018 figure is the pre-moratorium peak commissioning). 2025 figures are projections-from-pipeline-as-of-Q1-2026 for DE/GB/US/AU based on grid-connection queues and confirmed COD; treat as preliminary.'
);
